// Parse Gemini response for plan JSON
let text = '';
try {
  text = $input.first().json.candidates[0].content.parts[0].text || '';
} catch(e) {
  text = '';
}

// Clean markdown code fences
text = text.trim().replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();

try {
  const suggestions = JSON.parse(text);
  return [{ json: { suggestions, raw: text } }];
} catch (e) {
  return [{
    json: {
      suggestions: [
        {
          day: 5,
          platform: 'both',
          title: '[PARSE ERROR] Content idea',
          written_gist: 'The AI returned content that could not be parsed as JSON. Raw text is included below.',
          visual_gist: 'Abstract graphic representing data processing'
        }
      ],
      raw: text,
      parseError: e.message
    }
  }];
}

// Parse fallback Gemini response or return mock plan
let text = '';
try {
  const json = $input.first().json;
  if (json.candidates) {
    text = json.candidates[0].content.parts[0].text || '';
  }
} catch(e) {}

if (text) {
  text = text.trim().replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
  try {
    const suggestions = JSON.parse(text);
    return [{ json: { suggestions, raw: text } }];
  } catch(e) {}
}

// All failed — mock plan
return [{
  json: {
    suggestions: [
      {
        day: 5,
        platform: 'both',
        title: '[MOCK] System Update',
        written_gist: 'We are hitting API rate limits. This is a mock post generated by the fallback system.',
        visual_gist: 'Mock graphic showing a system alert.'
      },
      {
        day: 12,
        platform: 'facebook',
        title: '[MOCK] Industry Insights',
        written_gist: 'Mock insights. Please check your Gemini rate limits or configure billing.',
        visual_gist: 'Chart showing data trends.'
      },
      {
        day: 19,
        platform: 'instagram',
        title: '[MOCK] Behind the Scenes',
        written_gist: 'A fun look at how our team works day-to-day.',
        visual_gist: 'Candid team photo in a modern office.'
      },
      {
        day: 26,
        platform: 'both',
        title: '[MOCK] Weekly Wrap-Up',
        written_gist: 'Summarizing the key highlights and milestones from this week.',
        visual_gist: 'Infographic with weekly stats and achievements.'
      }
    ],
    raw: 'MOCK DATA — All Gemini models unavailable',
    isMock: true
  }
}];
